// Parse the OpenRouter response
const response = $input.first().json;
const content = response.choices[0].message.content;

// Extract title from first line or generate one
const lines = content.split('\n').filter(l => l.trim());
let subject = 'Newsletter AInspiration - Actualités IA';
let bodyContent = content;

// Try to extract title if it starts with # or is the first line
if (lines[0]) {
  const firstLine = lines[0].replace(/^#+\s*/, '').trim();
  if (firstLine.length < 100) {
    subject = firstLine;
    bodyContent = lines.slice(1).join('\n');
  }
}

// Add current date to subject
const today = new Date();
const dateStr = today.toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' });
subject = `${subject} - ${dateStr}`;

// Get subscribers from previous node
const subscribers = $('Récupérer Abonnés Actifs').all();

// Convert markdown-style content to HTML
function markdownToHtml(text) {
  return text.split('\n').map(line => {
    const trimmed = line.trim();
    if (!trimmed) return '';
    if (trimmed.startsWith('## ')) return `<h2 style="color: #4F46E5; margin-top: 25px; margin-bottom: 10px; font-size: 20px;">${trimmed.replace(/^## /, '')}</h2>`;
    if (trimmed.startsWith('### ')) return `<h3 style="color: #374151; margin-top: 20px; margin-bottom: 8px; font-size: 17px;">${trimmed.replace(/^### /, '')}</h3>`;
    if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) return `<li style="margin-bottom: 6px;">${trimmed.replace(/^[-*] /, '').replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')}</li>`;
    return `<p style="margin-bottom: 12px;">${trimmed.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')}</p>`;
  }).join('\n');
}

const htmlBody = markdownToHtml(bodyContent);

// Generate HTML version
const htmlContent = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${subject}</title>
</head>
<body style="font-family: 'Segoe UI', Arial, sans-serif; line-height: 1.7; max-width: 600px; margin: 0 auto; padding: 20px; background-color: #f3f4f6;">
  <div style="background-color: white; padding: 35px; border-radius: 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.08);">
    <!-- Header -->
    <div style="text-align: center; margin-bottom: 30px; padding-bottom: 20px; border-bottom: 2px solid #EEF2FF;">
      <h1 style="color: #4F46E5; margin: 0; font-size: 28px; letter-spacing: -0.5px;">AInspiration</h1>
      <p style="color: #6B7280; margin-top: 5px; font-size: 14px;">L'IA accessible aux PME</p>
    </div>

    <!-- Content -->
    <div style="color: #374151; font-size: 15px;">
      ${htmlBody}
    </div>

    <!-- CTA -->
    <div style="text-align: center; margin: 35px 0; padding: 25px; background: linear-gradient(135deg, #EEF2FF, #E0E7FF); border-radius: 10px;">
      <p style="margin: 0 0 15px 0; color: #374151; font-weight: 600;">Prêt à gagner 10h par semaine grâce à l'IA ?</p>
      <a href="https://ainspiration.eu/contact" style="display: inline-block; background-color: #4F46E5; color: white; padding: 14px 32px; text-decoration: none; border-radius: 8px; font-weight: bold; font-size: 15px;">Demander mon audit gratuit</a>
    </div>

    <!-- Footer -->
    <div style="border-top: 1px solid #E5E7EB; padding-top: 20px; margin-top: 30px; text-align: center; color: #6B7280; font-size: 12px;">
      <p style="margin: 5px 0; font-weight: bold;">AInspiration - L'IA au service des PME</p>
      <p style="margin: 5px 0;">Grand Place 50, 7850 Enghien, Belgique</p>
      <p style="margin: 5px 0;">Tel: +32 477 94 28 65</p>
      <p style="margin: 5px 0;"><a href="https://ainspiration.eu" style="color: #4F46E5;">www.ainspiration.eu</a></p>
      <p style="margin: 15px 0 5px 0;"><a href="{{UNSUBSCRIBE_URL}}" style="color: #9CA3AF; font-size: 11px;">Se désabonner de cette newsletter</a></p>
    </div>
  </div>
</body>
</html>
`;

return {
  subject,
  content: bodyContent,
  html_content: htmlContent,
  generated_at: new Date().toISOString(),
  subscribers: subscribers
};

// Prepare email for each subscriber in the batch
// HTTP response returns an array, so we need to get the first element
const savedNewsletter = $('Sauvegarder Newsletter').first().json;
const newsletter = Array.isArray(savedNewsletter) ? savedNewsletter[0] : savedNewsletter;
const subscribers = $('Récupérer Abonnés Actifs').all();

const emails = subscribers.map(sub => {
  const unsubscribeUrl = `https://ainspiration.eu/unsubscribe?token=${sub.json.unsubscribe_token}`;
  const htmlWithUnsubscribe = newsletter.html_content.replace('{{UNSUBSCRIBE_URL}}', unsubscribeUrl);

  return {
    to: sub.json.email,
    subject: newsletter.subject,
    html: htmlWithUnsubscribe,
    text: newsletter.content + `\n\n---\nPour vous désabonner: ${unsubscribeUrl}`,
    subscriber_id: sub.json.id,
    newsletter_id: newsletter.id
  };
});

return emails;

const response = $input.first().json;
const content = response.choices[0].message.content;

const lines = content.split('\n').filter(l => l.trim());
let subject = 'Newsletter AInspiration';
let bodyContent = content;

if (lines[0]) {
  const firstLine = lines[0].replace(/^#+\s*/, '').trim();
  if (firstLine.length < 100) {
    subject = firstLine;
    bodyContent = lines.slice(1).join('\n');
  }
}

return {
  subject,
  content: bodyContent
};

// Prepare emails from webhook body (manual send from admin)
const webhookData = $('Webhook Send').first().json.body;
const newsletter = webhookData.newsletter;
const subscribers = webhookData.subscribers || [];

if (!newsletter || !newsletter.subject) {
  throw new Error('Missing newsletter data in webhook body');
}

if (subscribers.length === 0) {
  throw new Error('No subscribers provided');
}

// Generate HTML if not provided
function markdownToHtml(text) {
  if (!text) return '';
  return text.split('\n').map(line => {
    const trimmed = line.trim();
    if (!trimmed) return '';
    if (trimmed.startsWith('## ')) return `<h2 style="color: #4F46E5; margin-top: 25px; margin-bottom: 10px; font-size: 20px;">${trimmed.replace(/^## /, '')}</h2>`;
    if (trimmed.startsWith('### ')) return `<h3 style="color: #374151; margin-top: 20px; margin-bottom: 8px; font-size: 17px;">${trimmed.replace(/^### /, '')}</h3>`;
    if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) return `<li style="margin-bottom: 6px;">${trimmed.replace(/^[-*] /, '').replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')}</li>`;
    return `<p style="margin-bottom: 12px;">${trimmed.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')}</p>`;
  }).join('\n');
}

const htmlBody = newsletter.html_content || `
<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head>
<body style="font-family: 'Segoe UI', Arial, sans-serif; line-height: 1.7; max-width: 600px; margin: 0 auto; padding: 20px; background-color: #f3f4f6;">
  <div style="background-color: white; padding: 35px; border-radius: 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.08);">
    <div style="text-align: center; margin-bottom: 30px; padding-bottom: 20px; border-bottom: 2px solid #EEF2FF;">
      <h1 style="color: #4F46E5; margin: 0; font-size: 28px;">AInspiration</h1>
      <p style="color: #6B7280; margin-top: 5px; font-size: 14px;">L'IA accessible aux PME</p>
    </div>
    <div style="color: #374151; font-size: 15px;">${markdownToHtml(newsletter.content)}</div>
    <div style="text-align: center; margin: 35px 0; padding: 25px; background: linear-gradient(135deg, #EEF2FF, #E0E7FF); border-radius: 10px;">
      <p style="margin: 0 0 15px 0; color: #374151; font-weight: 600;">Prêt à gagner 10h par semaine grâce à l'IA ?</p>
      <a href="https://ainspiration.eu/contact" style="display: inline-block; background-color: #4F46E5; color: white; padding: 14px 32px; text-decoration: none; border-radius: 8px; font-weight: bold;">Demander mon audit gratuit</a>
    </div>
    <div style="border-top: 1px solid #E5E7EB; padding-top: 20px; margin-top: 30px; text-align: center; color: #6B7280; font-size: 12px;">
      <p style="margin: 5px 0; font-weight: bold;">AInspiration - L'IA au service des PME</p>
      <p style="margin: 5px 0;">Grand Place 50, 7850 Enghien, Belgique</p>
      <p style="margin: 5px 0;">Tel: +32 477 94 28 65</p>
      <p style="margin: 5px 0;"><a href="https://ainspiration.eu" style="color: #4F46E5;">www.ainspiration.eu</a></p>
      <p style="margin: 15px 0 5px 0;"><a href="{{UNSUBSCRIBE_URL}}" style="color: #9CA3AF; font-size: 11px;">Se désabonner</a></p>
    </div>
  </div>
</body>
</html>`;

const emails = subscribers.map(sub => {
  const unsubscribeUrl = `https://ainspiration.eu/unsubscribe?token=${sub.unsubscribe_token}`;
  const html = htmlBody.replace(/\{\{UNSUBSCRIBE_URL\}\}/g, unsubscribeUrl);

  return {
    to: sub.email,
    subject: newsletter.subject,
    html: html,
    text: (newsletter.content || newsletter.subject) + `\n\n---\nPour vous désabonner: ${unsubscribeUrl}`,
    subscriber_id: sub.id,
    newsletter_id: newsletter.id
  };
});

return emails;
